public String fractionToDecimal(int numerator, int denominator) {
    if (numerator == 0) return "0";
    StringBuilder sb = new StringBuilder();
    // Handle sign
    if ((numerator < 0) ^ (denominator < 0)) sb.append("-");
    long num = Math.abs((long) numerator);
    long den = Math.abs((long) denominator);
    // Integer part
    sb.append(num / den);
    long remainder = num % den;
    if (remainder == 0) return sb.toString();
    sb.append(".");
    // Decimal part
    Map<Long, Integer> remainderMap = new HashMap<>();
    while (remainder != 0) {
        if (remainderMap.containsKey(remainder)) {
            sb.insert(remainderMap.get(remainder), "(");
            sb.append(")");
            break;
        }
        remainderMap.put(remainder, sb.length());
        remainder *= 10;
        sb.append(remainder / den);
        remainder %= den;
    }
    return sb.toString();
}

public boolean validPalindrome(String s) {
    int l = 0, r = s.length() - 1;
    while (l < r) {
        if (s.charAt(l) != s.charAt(r)) {
            // Try skipping left or right character
            return isPalin(s, l+1, r) || isPalin(s, l, r-1);
        }
        l++; r--;
    }
    return true;
}
private boolean isPalin(String s, int l, int r) {
    while (l < r) {
        if (s.charAt(l) != s.charAt(r)) return false;
        l++; r--;
    }
    return true;
}

// Space-optimised — O(n) time, O(1) space
public int climbStairs(int n) {
    if (n <= 2) return n;
    int prev2 = 1, prev1 = 2;
    for (int i = 3; i <= n; i++) {
        int curr = prev1 + prev2; // Fibonacci recurrence
        prev2 = prev1;
        prev1 = curr;
    }
    return prev1;
}
// Brute force for progression demo
private int helper(int n, int[] memo) {
    if (n <= 2) return n;
    if (memo[n] != 0) return memo[n];
    return memo[n] = helper(n-1, memo) + helper(n-2, memo);
}

public class MyVector<T> {
    private Object[] data;
    private int size;
    private static final int INITIAL_CAPACITY = 10;

    public MyVector() {
        data = new Object[INITIAL_CAPACITY];
        size = 0;
    }

    // O(1)
    public T get(int i) {
        if (i < 0 || i >= size) throw new IndexOutOfBoundsException();
        return (T) data[i];
    }

    // Amortised O(1)
    public void add(T e) {
        if (size == data.length) resize();
        data[size++] = e;
    }

    // O(n) — shifts elements
    public void remove(int i) {
        if (i < 0 || i >= size) throw new IndexOutOfBoundsException();
        System.arraycopy(data, i+1, data, i, size-i-1);
        data[--size] = null; // avoid memory leak
    }

    // O(1)
    public int size() { return size; }

    private void resize() {
        Object[] newData = new Object[data.length * 2];
        System.arraycopy(data, 0, newData, 0, size);
        data = newData;
    }
}

public int[] searchRange(int[] nums, int target) {
    return new int[]{findFirst(nums, target), findLast(nums, target)};
}
private int findFirst(int[] nums, int target) {
    int l = 0, r = nums.length - 1, result = -1;
    while (l <= r) {
        int mid = l + (r - l) / 2;
        if (nums[mid] == target) { result = mid; r = mid - 1; } // keep searching left
        else if (nums[mid] < target) l = mid + 1;
        else r = mid - 1;
    }
    return result;
}
private int findLast(int[] nums, int target) {
    int l = 0, r = nums.length - 1, result = -1;
    while (l <= r) {
        int mid = l + (r - l) / 2;
        if (nums[mid] == target) { result = mid; l = mid + 1; } // keep searching right
        else if (nums[mid] < target) l = mid + 1;
        else r = mid - 1;
    }
    return result;
}

class MedianFinder {
    private PriorityQueue<Integer> maxHeap; // lower half
    private PriorityQueue<Integer> minHeap; // upper half

    public MedianFinder() {
        maxHeap = new PriorityQueue<>(Collections.reverseOrder());
        minHeap = new PriorityQueue<>();
    }

    public void addNum(int num) {
        maxHeap.offer(num);              // always add to lower half first
        minHeap.offer(maxHeap.poll());   // balance: push max of lower to upper
        if (minHeap.size() > maxHeap.size()) // maintain invariant
            maxHeap.offer(minHeap.poll());
    }

    public double findMedian() {
        if (maxHeap.size() > minHeap.size()) return maxHeap.peek();
        return (maxHeap.peek() + minHeap.peek()) / 2.0;
    }
}

// BST LCA — O(h) time, O(1) space
public TreeNode lcaBST(TreeNode root, TreeNode p, TreeNode q) {
    while (root != null) {
        if (p.val < root.val && q.val < root.val)
            root = root.left;
        else if (p.val > root.val && q.val > root.val)
            root = root.right;
        else
            return root; // split point = LCA
    }
    return null;
}

// General Binary Tree LCA — O(n) time
public TreeNode lcaGeneral(TreeNode root, TreeNode p, TreeNode q) {
    if (root == null || root == p || root == q) return root;
    TreeNode left  = lcaGeneral(root.left, p, q);
    TreeNode right = lcaGeneral(root.right, p, q);
    if (left != null && right != null) return root; // p and q on different sides
    return left != null ? left : right; // propagate found node up
}

public boolean hasCycle(String s) {
    int n = s.length();
    int slow = 0, fast = 0;
    do {
        slow = nextIndex(s, slow, n);
        fast = nextIndex(s, nextIndex(s, fast, n), n);
        if (fast == slow) return true;
    } while (fast != 0); // back to start = no cycle found
    return false;
}
private int nextIndex(String s, int i, int n) {
    return (i + (s.charAt(i) - 'a' + 1)) % n;
}
// Alternative: HashSet — O(n) space
public boolean hasCycleSet(String s) {
    Set<Integer> visited = new HashSet<>();
    int idx = 0;
    while (visited.add(idx)) {
        idx = (idx + s.charAt(idx)) % s.length();
    }
    return true; // always cycles in bounded index space
}

public int calculate(String s) {
    Deque<Integer> nums = new ArrayDeque<>();
    Deque<Character> ops = new ArrayDeque<>();
    int i = 0;
    while (i < s.length()) {
        char c = s.charAt(i);
        if (c == ' ') { i++; continue; }
        if (Character.isDigit(c)) {
            int num = 0;
            while (i < s.length() && Character.isDigit(s.charAt(i)))
                num = num * 10 + (s.charAt(i++) - '0');
            nums.push(num); continue;
        } else if (c == '(') {
            ops.push(c);
        } else if (c == ')') {
            while (ops.peek() != '(') apply(nums, ops);
            ops.pop(); // remove '('
        } else { // operator
            while (!ops.isEmpty() && ops.peek() != '(' && prec(ops.peek()) >= prec(c))
                apply(nums, ops);
            ops.push(c);
        }
        i++;
    }
    while (!ops.isEmpty()) apply(nums, ops);
    return nums.pop();
}
private int prec(char op) {
    return (op == '*' || op == '/') ? 2 : 1;
}
private void apply(Deque<Integer> nums, Deque<Character> ops) {
    int b = nums.pop(), a = nums.pop();
    switch (ops.pop()) {
        case '+': nums.push(a + b); break;
        case '-': nums.push(a - b); break;
        case '*': nums.push(a * b); break;
        case '/': nums.push(a / b); break;
    }
}

public int maxSumPath(int[][] grid) {
    int m = grid.length, n = grid[0].length;
    int[][] dp = new int[m][n];
    // Initialize first column
    for (int i = 0; i < m; i++) dp[i][0] = grid[i][0];
    // Fill left to right
    for (int j = 1; j < n; j++) {
        for (int i = 0; i < m; i++) {
            dp[i][j] = grid[i][j]; // start with cell value
            // From left
            dp[i][j] = Math.max(dp[i][j], dp[i][j-1] + grid[i][j]);
            // From diagonal up-left
            if (i > 0) dp[i][j] = Math.max(dp[i][j], dp[i-1][j-1] + grid[i][j]);
            // From diagonal down-left
            if (i < m-1) dp[i][j] = Math.max(dp[i][j], dp[i+1][j-1] + grid[i][j]);
        }
    }
    int max = Integer.MIN_VALUE;
    for (int i = 0; i < m; i++) max = Math.max(max, dp[i][n-1]);
    return max;
}

// Two-pointer — O(n) time, O(1) space
public int trap(int[] height) {
    int l = 0, r = height.length - 1;
    int leftMax = 0, rightMax = 0, water = 0;
    while (l < r) {
        if (height[l] < height[r]) {
            if (height[l] >= leftMax) leftMax = height[l];
            else water += leftMax - height[l];
            l++;
        } else {
            if (height[r] >= rightMax) rightMax = height[r];
            else water += rightMax - height[r];
            r--;
        }
    }
    return water;
}
// DP precompute — O(n) time, O(n) space
public int trapDP(int[] h) {
    int n = h.length;
    int[] lMax = new int[n], rMax = new int[n];
    lMax[0] = h[0]; rMax[n-1] = h[n-1];
    for (int i=1;i<n;i++) lMax[i] = Math.max(lMax[i-1], h[i]);
    for (int i=n-2;i>=0;i--) rMax[i] = Math.max(rMax[i+1], h[i]);
    int water = 0;
    for (int i=0;i<n;i++) water += Math.min(lMax[i], rMax[i]) - h[i];
    return water;
}

class LRUCache {
    private class Node {
        int key, val;
        Node prev, next;
        Node(int k, int v) { key = k; val = v; }
    }
    private Map<Integer, Node> map;
    private Node head, tail; // dummy nodes
    private int cap;

    public LRUCache(int capacity) {
        cap = capacity;
        map = new HashMap<>();
        head = new Node(0, 0); tail = new Node(0, 0);
        head.next = tail; tail.prev = head;
    }

    public int get(int key) {
        if (!map.containsKey(key)) return -1;
        Node n = map.get(key);
        remove(n);
        addToHead(n);
        return n.val;
    }

    public void put(int key, int value) {
        if (map.containsKey(key)) {
            Node n = map.get(key);
            n.val = value;
            remove(n); addToHead(n);
        } else {
            Node n = new Node(key, value);
            map.put(key, n);
            addToHead(n);
            if (map.size() > cap) {
                Node lru = tail.prev;
                remove(lru);
                map.remove(lru.key);
            }
        }
    }

    private void addToHead(Node n) {
        n.next = head.next; n.prev = head;
        head.next.prev = n; head.next = n;
    }
    private void remove(Node n) {
        n.prev.next = n.next; n.next.prev = n.prev;
    }

    // Thread-safe extension
    // private final ReentrantReadWriteLock lock = new ReentrantReadWriteLock();
    // get(): lock.readLock().lock() ... finally lock.readLock().unlock()
    // put(): lock.writeLock().lock() ... finally lock.writeLock().unlock()
}

class StoreVisitTracker {
    // storeId -> date -> Set<customerId>
    private Map<String, Map<String, Set<String>>> visits = new HashMap<>();

    public void addVisit(String storeId, String date, String customerId) {
        visits
            .computeIfAbsent(storeId, k -> new HashMap<>())
            .computeIfAbsent(date, k -> new HashSet<>())
            .add(customerId);
    }

    // O(1) query
    public boolean hasMultipleVisitors(String storeId, String date) {
        Map<String, Set<String>> dateMap = visits.get(storeId);
        if (dateMap == null) return false;
        Set<String> customers = dateMap.get(date);
        return customers != null && customers.size() >= 2;
    }
}
